 using Microsoft.ML;
 using Microsoft.ML.Data;
 using TicketClassifier.Models;

 namespace TicketClassifier.Services;

 public class TicketClassifierService
 {
     private readonly MLContext _mlContext;
     private readonly ITransformer _model;
     private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
     private readonly EvaluationMetrics _metrics;
     private readonly string[] _categoryLabels;

     public TicketClassifierService(string dataPath)
     {
         _mlContext = new MLContext(seed: 42);

         var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
             dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

         // With a small dataset, train on all data and evaluate on the same set
         // to report metric structure. In production, use a proper train/test split.
         _model = TrainModel(dataView);
         _metrics = Evaluate(dataView);
         _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);

         // Extract the label mapping so we can pair scores with category names
         var labelBuffer = new VBuffer<ReadOnlyMemory<char>>();
         _predictionEngine.OutputSchema["Score"]
             .GetSlotNames(ref labelBuffer);
         _categoryLabels = labelBuffer.DenseValues()
             .Select(v => v.ToString())
             .ToArray();
     }

     private ITransformer TrainModel(IDataView data)
     {
         var pipeline = _mlContext.Transforms.Conversion
                 .MapValueToKey("Label", nameof(TicketData.Category))
             .Append(_mlContext.Transforms.Text
                 .FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
             .Append(_mlContext.Transforms.Text
                 .FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
             .Append(_mlContext.Transforms.Concatenate("Features",
                 "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
             .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
             .Append(_mlContext.MulticlassClassification.Trainers
                 .SdcaMaximumEntropy("Label", "Features"))
             .Append(_mlContext.Transforms.Conversion
                 .MapKeyToValue("PredictedLabel"));

         return pipeline.Fit(data);
     }

     private EvaluationMetrics Evaluate(IDataView data)
     {
         var predictions = _model.Transform(data);
         var mlMetrics = _mlContext.MulticlassClassification.Evaluate(predictions, "Label");

         var result = new EvaluationMetrics
         {
             MacroAccuracy = mlMetrics.MacroAccuracy,
             MicroAccuracy = mlMetrics.MicroAccuracy,
             LogLoss = mlMetrics.LogLoss,
             LogLossReduction = mlMetrics.LogLossReduction
         };

         for (var i = 0; i < mlMetrics.PerClassLogLoss.Count; i++)
         {
             result.PerCategory.Add(new CategoryMetric
             {
                 Category = i < _categoryLabels?.Length ? _categoryLabels[i] : $"Class {i}",
                 Precision = mlMetrics.ConfusionMatrix.PerClassPrecision[i],
                 Recall = mlMetrics.ConfusionMatrix.PerClassRecall[i]
             });
         }

         return result;
     }

     public EvaluationMetrics GetMetrics() => _metrics;

     public PredictionResponse Predict(TicketRequest request)
     {
         var ticketData = new TicketData
         {
             Subject = request.Subject,
             Description = request.Description,
             Priority = request.Priority
         };

         var prediction = _predictionEngine.Predict(ticketData);

         var confidence = new Dictionary<string, float>();
         for (var i = 0; i < _categoryLabels.Length; i++)
         {
             confidence[_categoryLabels[i]] = prediction.Score[i];
         }

         return new PredictionResponse
         {
             PredictedCategory = prediction.PredictedCategory,
             Confidence = confidence
         };
     }
 }

